//理学療法士管理画面
"use client";

import { useState } from "react";

export default function PTRegisterPage() {
    // 状態（入力内容）を管理する箱
    const [name, setName] = useState("");
    const [specialty, setSpecialty] = useState("運動器");
    const [experience, setExperience] = useState(0);

    const handleSave = () => {
        alert(name + " 先生の情報を保存しました");
    };

    return (
        <div style={{ padding: "40px", maxWidth: "600px", margin: "0 auto" }}>
            <h1>理学療法士：プロフィール登録</h1>
            <p style={{ color: "#666" }}>あなたの専門性を登録しましょう。</p>

            <div style={{ marginTop: "20px" }}>
                <label style={{ display: "block", fontWeight: "bold" }}>氏名</label>
                <input 
                    style={{ width: "100%", padding: "10px", margin: "10px 0" }} 
                    value={name} 
                    onChange={(e) => { setName(e.target.value); }}
                    placeholder="例：山田 太郎"
                />

                <label style={{ display: "block", fontWeight: "bold" }}>専門分野</label>
                <select 
                    style={{ width: "100%", padding: "10px", margin: "10px 0" }}
                    value={specialty}
                    onChange={(e) => { setSpecialty(e.target.value); }}
                >
                    <option value="運動器">運動器</option>
                    <option value="中枢神経">中枢神経</option>
                    <option value="呼吸器">呼吸器</option>
                    <option value="高齢者">高齢者</option>
                </select>

                <label style={{ display: "block", fontWeight: "bold" }}>経験年数</label>
                <input 
                    type="number"
                    style={{ width: "100%", padding: "10px", margin: "10px 0" }} 
                    value={experience} 
                    onChange={(e) => { setExperience(Number(e.target.value)); }}
                />

                <button 
                    onClick={handleSave}
                    style={{ 
                        width: "100%", 
                        padding: "15px", 
                        backgroundColor: "#28a745", 
                        color: "white", 
                        border: "none", 
                        borderRadius: "5px", 
                        fontWeight: "bold", 
                        cursor: "pointer" 
                    }}
                >
                    プロフィールを公開する
                </button>
            </div>
        </div>
    );
}